INSERT INTO skill_branches VALUES(1,'Backend Shield','Деньги, рынок, commercial delivery','Backend, IoT/Networks','Сервис переживает сбои и дубли','Продаётся даже без железа');
INSERT INTO skill_branches VALUES(2,'Systems Blade','C, память, Linux, toolchain','C/Systems, Linux','Gateway как Linux service','Не зависишь от фреймворков');
INSERT INTO skill_branches VALUES(3,'Hardware Hands','Пайка, измерения, схемы','Electronics, Debug','Доказать баг измерением','ИИ не трогает физику');
INSERT INTO skill_branches VALUES(4,'Firmware Fire','MCU, firmware, RTOS','Firmware, RTOS','FreeRTOS firmware с watchdog','Реальный мир + timing');
INSERT INTO skill_branches VALUES(5,'Board Craft','KiCad, PCB, ревизии','PCB','Carrier board v1','Ответственность за изделие');
INSERT INTO skill_branches VALUES(6,'Test Alchemy','Python HIL, serial, CI','Testing','Firmware test runner','Связывает backend и embedded');
INSERT INTO skill_branches VALUES(7,'Security Wards','Device identity, updates, threat model','Security','Signed update simulation','Защита от продуктовых рисков');
INSERT INTO roadmap_stages VALUES(0,'Career Shield','','Backend core','A',1,'Backend','Python backend, SQL, Docker, Linux, тесты, миграции, логирование','FastAPI/Django docs; PostgreSQL docs; Docker docs; Паттерны разработки на Python; Чистая архитектура','Backend telemetry API: devices, events, PostgreSQL, Docker Compose, tests','Поднимаешь проект с БД, миграциями, логами, тестами и Docker без постоянного копипаста','Ревью архитектуры, edge cases, тест-кейсы','Backend остаётся источником денег и быстрым рынком входа');
INSERT INTO roadmap_stages VALUES(1,'Backend Reliability','','Очереди и живучесть','A',2,'Backend','Redis/RabbitMQ, Celery/TaskIQ/RQ, retry, idempotency, structured logs, healthchecks, транзакции','PostgreSQL docs; Redis docs; Celery/TaskIQ docs; CMU 15-445 выборочно','Сервис переживает дубли, падение worker, временную недоступность очереди/БД','Есть тесты на дубли, падения worker, временную недоступность очереди/БД','Сценарии отказов и плохие данные','Навыки продаются даже без embedded');
INSERT INTO roadmap_stages VALUES(2,'C as Gateway to Hardware','','C / memory / tooling','A',3,'C/Systems','C, указатели, память, структуры, bitwise, Make/CMake, gdb, sanitizers, ring buffer','Beej’s Guide to C; Modern C; K. N. King C Programming: A Modern Approach опционально','C device simulator: бинарные пакеты, checksum, encode/decode, отправка в backend/gateway','Объясняешь указатель, стек/кучу, endianness, битовую маску и отлаживаешь segfault','Объяснение UB, тесты, ревью C-кода','C — база firmware, embedded Linux и systems');
INSERT INTO roadmap_stages VALUES(3,'Computer Architecture','','Под кодом','A',4,'C/Systems','CPU, регистры, память, stack frame, cache, interrupts, I/O, memory-mapped I/O','Berkeley CS61C или MIT 6.004; Nand2Tetris Part I выборочно','Разбор assembly простых C-программ; мини-VM или binary parser','Понимаешь, как C превращается в машинное выполнение','Объяснение assembly и memory layout','Защита от фреймворк-зависимости');
INSERT INTO roadmap_stages VALUES(4,'Linux Systems','','Backend/system bridge','A',5,'Linux','Processes, threads, signals, files, sockets, permissions, systemd, journalctl, serial devices','OSTEP; MIT 6.1810 выборочно','Python gateway как Linux-сервис: systemd, logs, config, restart, graceful shutdown','Gateway запускается как сервис, логируется, восстанавливается и переживает сбои','Failure scenarios, systemd/debug checklist','Embedded Linux и backend пересекаются здесь');
INSERT INTO roadmap_stages VALUES(5,'Networks and IoT Protocols','','Связь device/backend','A',6,'IoT/Networks','TCP/UDP basics, HTTP, WebSocket/SSE, MQTT, reconnect, timeouts, backoff, device identity','Stanford CS144 выборочно; MQTT/Mosquitto docs; Beej Network Programming позже','Gateway → MQTT broker → backend worker → PostgreSQL → dashboard','Система переживает потерю сети, дубли и повторную доставку','Моделирование сетевых сбоев','IoT/backend — лучший мост к embedded');
INSERT INTO roadmap_stages VALUES(6,'Electronics Hands-On','','Физический минимум','A',7,'Electronics','Закон Ома, питание, земля, LED, кнопки, pull-up/pull-down, конденсаторы, датчики, мультиметр, пайка','Электроника для начинающих; All About Circuits; MIT 6.002 выборочно','Breadboard: кнопка, LED, датчик, питание; потом пайка на макетной плате','Умеешь измерить напряжение, найти короткое, прозвонить цепь, не путать GND/VCC','Чеклист проверки схемы','Физические измерения ИИ за тебя не сделает');
INSERT INTO roadmap_stages VALUES(7,'First Microcontroller','','Bare-metal firmware','A',8,'Firmware','GPIO, UART, timers, interrupts, PWM, ADC, I2C, SPI, watchdog','Raspberry Pi Pico C SDK или STM32CubeIDE/ST docs; UT Austin Shape The World','Плата читает датчик и отправляет данные по UART в Python gateway','Устройство стабильно шлёт данные несколько часов; объясняешь путь данных','Разбор datasheet и регистра, обязательная ручная проверка','Дешёвый вход в firmware без риска бросить backend');
INSERT INTO roadmap_stages VALUES(8,'Instrumentation and Debug','','Измерять, а не гадать','A',9,'Debug','Multimeter, logic analyzer, serial logs, baud rate, I2C scan, SPI decode, test points, fault tree','Документация инструментов; Saleae-style tutorials; datasheets','Debug-сценарии: неверный baud rate, оборванный провод, нет GND, конфликт I2C address','Можешь доказать причину проблемы измерением или логом','Дерево гипотез и план проверок','Главный анти-ИИ навык: физическая диагностика');
INSERT INTO roadmap_stages VALUES(9,'Firmware as Product','','Firmware architecture','A',10,'Firmware','State machines, drivers, HAL boundaries, error codes, config, logging, protocol versioning, memory limits','UT Austin/Valvano Embedded Systems; datasheets; vendor docs','Firmware v1: driver layer, protocol layer, app layer, UART CLI, error counters','Код имеет слои, протокол и диагностику, а не один main.c на 800 строк','Ревью структуры и failure modes','Делает проект инженерным продуктом');
INSERT INTO roadmap_stages VALUES(10,'FreeRTOS','','Real-time thinking','B',11,'RTOS','Tasks, queues, semaphores, mutex, timers, priorities, ISR-to-task, watchdog, stack/heap','FreeRTOS Kernel Book/docs','Sensor task, comm task, health/watchdog task, queue, error stats','Понимаешь priority inversion, ISR limits, stack overflow, watchdog recovery','Задачи и mock interview по RTOS','RTOS — важный слой для настоящего embedded');
INSERT INTO roadmap_stages VALUES(11,'C++ for Embedded/Linux','','Расширить рынок','B',12,'C/Systems','RAII, classes, value/reference, move basics, templates minimally, STL cautiously, no-exceptions/no-rtti awareness','LearnCpp; C++ Core Guidelines выборочно; vendor examples','C++ firmware/tool module без магии или C++ Linux utility','Понимаешь, где C++ помогает, а где опасен','Сравнение C/C++ решений','В embedded/Linux вакансиях C++ встречается часто');
INSERT INTO roadmap_stages VALUES(12,'PCB v0: Carrier Board','','Первая плата без героизма','B',13,'PCB','KiCad, schematic, footprints, ERC/DRC, BOM, connectors, test points, decoupling, silkscreen','KiCad docs; datasheets; manufacturer design rules','Carrier board: dev-модуль, датчик, кнопка, LED, разъёмы, test points','Плата проходит ERC/DRC, заказана, спаяна, прозвонена и работает','Чеклист DRC/ERC/BOM','Carrier board снижает цену ошибки');
INSERT INTO roadmap_stages VALUES(13,'PCB v1: Revision Discipline','','Инженерный цикл','B',14,'PCB','Ошибки v0, ECO, ревизии, BOM, альтернативы компонентов, DFM/DFT, assembly notes','KiCad docs; datasheets; manufacturing rules','Ревизия v1: исправления, test points, подписи, документация','Объясняешь каждое изменение v1 и почему v0 была плохой','Changelog и risk list','Ревизии важнее “сразу идеальной платы”');
INSERT INTO roadmap_stages VALUES(14,'Embedded Linux','','Мост к промышленности','B',15,'Linux','Cross-compilation, Buildroot basics, systemd, device files, GPIO/serial, kernel/user boundary','Bootlin Embedded Linux materials; OSTEP; MIT 6.1810 выборочно','Linux gateway на SBC: serial/MQTT/logs/local buffering; позже Buildroot image','Можешь собрать gateway, запустить сервис и диагностировать его','Конфиги и логи','Embedded Linux ближе к backend, чем чистая firmware');
INSERT INTO roadmap_stages VALUES(15,'Zephyr / Modern Embedded','','Production-style RTOS','C',16,'RTOS','West, CMake, Kconfig, Devicetree, board configs, drivers, samples','Zephyr docs','Портировать sensor/logging app на Zephyr','Понимаешь Kconfig/Devicetree/source и структуру Zephyr-проекта','Навигация по docs','Zephyr полезен, но не первый RTOS');
INSERT INTO roadmap_stages VALUES(16,'Hardware Test Automation','','Сильный мост из Python','B',17,'Testing','pytest, serial, flashing scripts, log parsing, reports, HIL basics, CI','pytest docs; pyserial docs; vendor flashing tools','Python test runner: прошивает/перезапускает устройство, читает UART, проверяет команды','Тесты находят реальные ошибки firmware/protocol','Генерация test cases и fault injection','Рыночный мост: Python + embedded team');
INSERT INTO roadmap_stages VALUES(17,'Security and CPS Thinking','','Зрелость системы','C',18,'Security','Device auth, secrets, TLS, firmware versioning, signing concept, rollback, fault modes, real-time constraints','OWASP IoT checklist; Berkeley EECS149 + Lee/Seshia; vendor security docs','Versioning + signed update simulation + fault injection scenarios','Можешь объяснить, как система ломается, диагностируется, обновляется и восстанавливается','Threat modeling assistant','Security/CPS выдерживает смену технологий');
